// ── Build complete file for each language ──
for (const lang of ['ja','ko','de','fr','it']) {
  const existing = JSON.parse(fs.readFileSync(`src/i18n/locales/${lang}.json`, 'utf8'));
  const translations = t[lang];

  // Deep-merge translations into the existing structure
  for (const [keyPath, value] of Object.entries(translations)) {
    const parts = keyPath.split('.');
    let obj = existing;
    for (let i = 0; i < parts.length - 1; i++) {
      if (!obj[parts[i]]) obj[parts[i]] = {};
      obj = obj[parts[i]];
    }
    obj[parts[parts.length - 1]] = value;
  }

  // Write complete file
  fs.writeFileSync(`src/i18n/locales/${lang}.json`, JSON.stringify(existing, null, 2) + '\n');
  console.log(`${lang}.json written`);
}

// Verify all files have same key count as zh.json
const zh = JSON.parse(fs.readFileSync('src/i18n/locales/zh.json', 'utf8'));
function countKeys(obj, prefix='') {
  let n = 0;
  for (const k of Object.keys(obj)) {
    n++;
    if (typeof obj[k] === 'object' && obj[k] !== null && !Array.isArray(obj[k])) {
      n += countKeys(obj[k], prefix + k + '.');
    }
  }
  return n;
}
const zhCount = countKeys(zh);
console.log(`\nzh.json: ${zhCount} total keys (reference)`);
for (const lang of ['en','ja','ko','de','fr','it']) {
  const d = JSON.parse(fs.readFileSync(`src/i18n/locales/${lang}.json`, 'utf8'));
  const c = countKeys(d);
  const missing = zhCount - c;
  console.log(`${lang}.json: ${c} keys` + (missing > 0 ? ` (MISSING ${missing})` : ' ✓'));
}
